#!/bin/bash
make
echo $'\n'test$'\t'42
./converter 42
echo $'\n'test$'\t'-69
./converter -69
echo $'\n'test$'\t'0.
./converter 0.
echo $'\n'test$'\t'a
./converter a
echo $'\n'test$'\t'"$'\t'"
./converter $'\t'
echo $'\n'test$'\t'alfa
./converter alfa
echo $'\n'test$'\t'"1025 35"
./converter "1025 35"
echo $'\n'test$'\t'.32
./converter .32
echo $'\n'test$'\t'1968.
./converter 1968.
echo $'\n'test$'\t'-69.00000
./converter -69.00000
echo $'\n'test$'\t'39.000f
./converter 39.000f
echo $'\n'test$'\t'nan
./converter nan
echo $'\n'test$'\t'inf
./converter inf
echo $'\n'test$'\t'+inf
./converter +inf
echo $'\n'test$'\t'9999999999999999999999999999999999
./converter 9999999999999999999999999999999999
echo $'\n'test$'\t'9999999999999999999999999999999999f
./converter 9999999999999999999999999999999999f
echo $'\n'test$'\t'9999999999999999999999999999999999.f
./converter 9999999999999999999999999999999999.f
echo $'\n'test$'\t'999999999999999999999999999999999999999999999999999
./converter 999999999999999999999999999999999999999999999999999
echo $'\n'test$'\t'999999999999999999999999999999999999999999999999999.f
./converter 999999999999999999999999999999999999999999999999999.f
echo $'\n'test$'\t'999999999999999999999999999999999999999999999999999.0
./converter 999999999999999999999999999999999999999999999999999.0
echo $'\n'test$'\t'-0.123456000
./converter -0.123456000
echo $'\n'test$'\t'-0
./converter -0
ARG="+32"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG=""
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG=".0f"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="00001.1230000"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="000-01.1230000"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="00001.1230000f"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="-00001.1230000f"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="+00001.1230000f"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="+000091.1230000"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="-000091.1230000"
echo $'\n'test$'\t'$ARG
./converter $ARG
ARG="X"
echo $'\n'test$'\t'$ARG
./converter $ARG

make fclean